export const meta = {
  name: 'explore-opencore-codebase',
  description: '深度探索 OpenCoreAnalysisKit 代码库并构建完整知识管理系统（含自动知识沉淀）',
  phases: [
    { title: '项目扫描', detail: '扫描文件结构、依赖和复杂度' },
    { title: '架构分析', detail: '识别逻辑层次和模块关系' },
    { title: '领域分析', detail: '提取业务流程和领域知识' },
    { title: '文件批量分析', detail: '并行分析核心源文件' },
    { title: '知识沉淀', detail: '自动保存关键知识到文档' },
    { title: '索引更新', detail: '自动更新知识库索引' },
    { title: '知识系统初始化', detail: '配置自动更新和索引系统' }
  ]
}

// ============================================================
// 工具函数：知识沉淀
// ============================================================

/**
 * 根据分析结果自动判断需要沉淀的知识主题
 */
function detectKnowledgeToPreserve(fileAnalyses, archResult, domainResult) {
  const knowledgeTopics = []

  // 从架构分析中提取需要沉淀的主题
  if (archResult?.layers) {
    archResult.layers.forEach(layer => {
      if (layer.keyComponents?.length > 0) {
        knowledgeTopics.push({
          type: 'architecture',
          title: `${layer.name} 架构分析`,
          content: layer,
          priority: 'high'
        })
      }
    })
  }

  // 从文件分析中提取关键技术点
  if (fileAnalyses?.length > 0) {
    fileAnalyses.forEach(analysis => {
      if (analysis?.insights) {
        knowledgeTopics.push({
          type: 'implementation',
          title: `${analysis.filePath} 实现分析`,
          content: analysis,
          priority: 'medium'
        })
      }
      if (analysis?.designPatterns?.length > 0) {
        knowledgeTopics.push({
          type: 'design-pattern',
          title: `${analysis.filePath} 设计模式`,
          content: analysis.designPatterns,
          priority: 'medium'
        })
      }
    })
  }

  // 从领域分析中提取业务知识
  if (domainResult?.domains) {
    domainResult.domains.forEach(domain => {
      knowledgeTopics.push({
        type: 'domain',
        title: `${domain.name} 领域知识`,
        content: domain,
        priority: 'high'
      })
    })
  }

  return knowledgeTopics
}

/**
 * 生成知识文档内容
 */
function generateKnowledgeDoc(topic) {
  const timestamp = new Date().toISOString().split('T')[0]
  const typeLabel = {
    'architecture': '架构',
    'implementation': '实现',
    'design-pattern': '设计模式',
    'domain': '领域'
  }[topic.type] || '技术'

  let content = `# ${topic.title}\n\n`
  content += `> **类型**: ${typeLabel} | **优先级**: ${topic.priority} | **生成时间**: ${timestamp}\n\n`
  content += `---\n\n`

  // 问题背景
  content += `## 问题背景\n\n`
  content += `暂无\n\n`

  // 核心流程
  content += `## 核心流程\n\n`
  if (typeof topic.content === 'object') {
    content += '```\n' + JSON.stringify(topic.content, null, 2) + '\n```\n\n'
  } else {
    content += topic.content + '\n\n'
  }

  // 实现细节
  content += `## 实现细节\n\n`
  content += `暂无\n\n`

  // 应用场景
  content += `## 应用场景\n\n`
  content += `暂无\n\n`

  // 总结
  content += `## 总结\n\n`
  content += `-主题: ${topic.title}\n`
  content += `- 类型: ${typeLabel}\n`
  content += `- 生成时间: ${timestamp}\n`

  return content
}

/**
 * 获取下一个知识文档编号
 */
function getNextDocNumber(docsDir) {
  const existingFiles = (docsDir.match(/\d{2}-.*?\.md/g) || [])
  let maxNum = 10
  existingFiles.forEach(f => {
    const num = parseInt(f.match(/^(\d{2})/)?.[1] || '0')
    if (num > maxNum) maxNum = num
  })
  return String(maxNum + 1).padStart(2, '0')
}

// ============================================================
// 阶段 1: 项目扫描
// ============================================================
phase('项目扫描')
log('开始扫描 OpenCoreAnalysisKit 项目结构...')

const scanResult = await agent(
  `扫描 /home/cwtrocks/OpenCoreAnalysisKit 项目：

   任务：
   1. 识别所有主要目录和源文件
   2. 检测使用的语言（C++）、构建系统（CMake/bash scripts）
   3. 分析第三方依赖（3rd-party 目录）
   4. 评估项目规模和复杂度
   5. 识别关键入口点（main函数、核心类）

   重点关注：
   - parser/ 目录（主要实现）
   - android/ 目录（ART 运行时镜像）
   - core/ 目录（核心解析逻辑）
   - command/ 目录（命令系统）

   输出结构化的项目概览`,
