export const meta = {
  name: 'explore-opencore-codebase',
  description: '深度探索 OpenCoreAnalysisKit 代码库并构建完整知识管理系统',
  phases: [
    { title: '项目扫描', detail: '扫描文件结构、依赖和复杂度' },
    { title: '架构分析', detail: '识别逻辑层次和模块关系' },
    { title: '领域分析', detail: '提取业务流程和领域知识' },
    { title: '文件批量分析', detail: '并行分析核心源文件' },
    { title: '知识整合', detail: '构建统一知识报告' },
    { title: '知识系统初始化', detail: '配置自动更新和索引系统' }
  ]
}

// ============================================================
// 阶段 1: 项目扫描
// ============================================================
phase('项目扫描')
log('开始扫描 OpenCoreAnalysisKit 项目结构...')

const scanResult = await agent(
  `扫描 /home/cwtrocks/OpenCoreAnalysisKit 项目：

   任务：
   1. 识别所有主要目录和源文件
   2. 检测使用的语言（C++）、构建系统（CMake/bash scripts）
   3. 分析第三方依赖（3rd-party 目录）
   4. 评估项目规模和复杂度
   5. 识别关键入口点（main函数、核心类）

   重点关注：
   - parser/ 目录（主要实现）
   - android/ 目录（ART 运行时镜像）
   - core/ 目录（核心解析逻辑）
   - command/ 目录（命令系统）

   输出结构化的项目概览`,
  {
    agentType: 'understand-anything:project-scanner',
    label: '扫描项目结构',
    schema: {
      type: 'object',
      properties: {
        projectName: { type: 'string' },
        languages: { type: 'array', items: { type: 'string' } },
        buildSystem: { type: 'string' },
        fileCount: { type: 'number' },
        keyDirectories: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              name: { type: 'string' },
              purpose: { type: 'string' },
              fileCount: { type: 'number' }
            }
          }
        },
        dependencies: { type: 'array', items: { type: 'string' } },
        entryPoints: { type: 'array', items: { type: 'string' } },
        complexity: { type: 'string' }
      },
      required: ['projectName', 'languages', 'fileCount']
    }
  }
)

log(`✓ 项目扫描完成: ${scanResult.fileCount} 个文件，主要语言 ${scanResult.languages.join(', ')}`)

// ============================================================
// 阶段 2: 架构分析
// ============================================================
phase('架构分析')
log('分析代码库的架构层次和模块依赖...')

const archResult = await agent(
  `分析 OpenCoreAnalysisKit 的软件架构:

   任务：
   1. 识别逻辑分层（UI层、命令层、运行时镜像层、核心解析层、平台抽象层）
   2. 分析模块间依赖关系和调用链
   3. 识别关键组件和设计模式
   4. 分析数据流向（从 coredump 加载到命令输出）

   参考 CLAUDE.md 中的架构说明：
   - parser/ 是主要入口和命令系统
   - android/ 镜像 AOSP 的 ART 运行时
   - core/ 处理底层 ELF 和内存操作

   输出分层架构和依赖图数据`,
  {
    agentType: 'understand-anything:architecture-analyzer',
    label: '分析架构层次',
    schema: {
      type: 'object',
      properties: {
        layers: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              name: { type: 'string' },
              description: { type: 'string' },
              keyComponents: { type: 'array', items: { type: 'string' } },
              dependencies: { type: 'array', items: { type: 'string' } }
            }
          }
        },
        designPatterns: { type: 'array', items: { type: 'string' } },
        dataFlow: { type: 'string' }
      },
      required: ['layers']
    }
  }
)

log(`✓ 识别了 ${archResult.layers.length} 个架构层次`)

// ============================================================
// 阶段 3: 领域分析
// ============================================================
phase('领域分析')
log('提取 Android coredump 分析领域的业务知识...')

const domainResult = await agent(
  `分析 OpenCoreAnalysisKit 的业务领域和核心概念:

   任务：
   1. 识别核心业务流程：
      - Coredump 文件加载和解析
      - ART 运行时状态恢复
      - Java 堆对象遍历和分析
      - 线程栈回溯
      - 符号解析

   2. 提取领域概念：
      - ELF Core 文件格式
      - ART Runtime 内存布局
      - HeapReference（32位压缩引用）
      - mirror::Class / mirror::Object
      - DEX 文件格式

   3. 分析命令系统：
      - class: 搜索类实例
      - space: 堆空间遍历
      - thread: 线程分析
      - top: 对象统计

   输出领域模型和业务流程`,
  {
    agentType: 'understand-anything:domain-analyzer',
    label: '提取领域知识',
    schema: {
      type: 'object',
      properties: {
        domains: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              name: { type: 'string' },
              description: { type: 'string' },
              keyConcepts: { type: 'array', items: { type: 'string' } },
              processes: { type: 'array', items: { type: 'string' } }
            }
          }
        },
        commands: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              name: { type: 'string' },
              purpose: { type: 'string' },
              implementation: { type: 'string' }
            }
          }
        }
      },
      required: ['domains']
    }
  }
)

log(`✓ 识别了 ${domainResult.domains.length} 个业务领域`)

// ============================================================
// 阶段 4: 文件批量分析（并行）
// ============================================================
phase('文件批量分析')
log('并行深度分析核心源文件...')

// 定义需要深度分析的核心文件（根据重要性分组）
const criticalFiles = [
  'parser/core_parser.cpp',           // 主入口
  'android/art/runtime/mirror/class.h',   // ART Class 镜像
  'android/art/runtime/mirror/object.h',  // ART Object 镜像
  'android/art/runtime/mirror/string.h',  // ART String 镜像
]

const commandFiles = [
  'parser/command/android/cmd_class.cpp',     // class 命令
  'parser/command/android/cmd_space.cpp',     // space 命令
  'parser/command/core/cmd_thread.cpp',    // thread 命令
  'parser/command/android/cmd_top.cpp',       // top 命令
]

const coreFiles = [
  'core/api/core.h',                      // 核心接口
  'android/android.cpp',              // Android 版本检测
]

const allFiles = [...criticalFiles, ...commandFiles, ...coreFiles]

const fileAnalyses = await pipeline(
  allFiles,
  // Stage 1: 并行读取并分析每个文件
  async (file) => {
    return await agent(
      `深度分析文件: ${file}

       任务：
       1. 提取主要类、结构体、函数定义
       2. 识别关键算法和数据结构
       3. 分析与其他模块的依赖关系
       4. 提取代码注释中的设计决策和领域知识
       5. 识别使用的设计模式（如命令模式、工厂模式）

       特别关注：
       - ART 运行时对象的内存布局
       - HeapReference 的 32 位压缩机制
       - 命令的注册和执行流程
       - ELF 文件解析逻辑

       输出结构化的文件分析报告`,
      {
        label: `分析 ${file.split('/').pop()}`,
        phase: '文件批量分析',
        schema: {
          type: 'object',
          properties: {
            filePath: { type: 'string' },
            fileType: { type: 'string' },
            mainClasses: {
              type: 'array',
              items: {
                type: 'object',
                properties: {
                  name: { type: 'string' },
                  purpose: { type: 'string' },
                  keyMethods: { type: 'array', items: { type: 'string' } }
                }
              }
            },
            keyAlgorithms: { type: 'array', items: { type: 'string' } },
            designPatterns: { type: 'array', items: { type: 'string' } },
            dependencies: { type: 'array', items: { type: 'string' } },
            insights: { type: 'string' }
          },
          required: ['filePath', 'mainClasses', 'insights']
        }
      }
    )
  }
)

const validAnalyses = fileAnalyses.filter(Boolean)
log(`✓ 完成 ${validAnalyses.length}/${allFiles.length} 个文件的深度分析`)

// ============================================================
// 阶段 5: 知识整合
// ============================================================
phase('知识整合')
log('整合所有分析结果，生成统一知识报告...')

const knowledgeReport = await agent(
  `整合以下分析结果，生成 OpenCoreAnalysisKit 的完整知识报告:

   输入数据：
   1. 项目扫描: ${JSON.stringify(scanResult, null, 2)}
   2. 架构分析: ${JSON.stringify(archResult, null, 2)}
   3. 领域分析: ${JSON.stringify(domainResult, null, 2)}
   4. 文件分析: ${JSON.stringify(validAnalyses, null, 2)}

   任务：
   1. 生成项目整体概览
   2. 总结关键架构决策和设计模式
   3. 提炼核心领域知识点
   4. 识别代码热点和关键路径
   5. 生成学习路径建议（新手如何快速上手）
   6. 列出潜在改进点和技术债务

   输出结构化的知识报告`,
  {
    label: '生成知识报告',
    schema: {
      type: 'object',
      properties: {
        overview: { type: 'string' },
        architectureHighlights: { type: 'array', items: { type: 'string' } },
        domainKnowledge: { type: 'array', items: { type: 'string' } },
        codeHotspots: { type: 'array', items: { type: 'string' } },
        learningPath: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              step: { type: 'number' },
              title: { type: 'string' },
              focus: { type: 'string' },
              files: { type: 'array', items: { type: 'string' } }
            }
          }
        },
        improvements: { type: 'array', items: { type: 'string' } }
      },
      required: ['overview', 'architectureHighlights', 'learningPath']
    }
  }
)

log(`✓ 知识整合完成`)

// ============================================================
// 阶段 6: 知识系统初始化（新增）
// ============================================================
phase('知识系统初始化')
log('初始化知识管理系统...')

// 6.1 生成文档索引
log('→ 生成文档索引...')
const indexResult = await agent(
  `运行文档索引生成器:

   执行: python3 scripts/generate-doc-index.py

   任务：
   1. 扫描 docs/exploration/ 目录
   2. 提取所有文档的标题和摘要
   3. 生成 INDEX.md 文件
   4. 按类别分组展示

   输出执行结果`,
  {
    label: '生成文档索引',
    phase: '知识系统初始化'
  }
)

log(`✓ 文档索引已生成`)

// 6.2 初始化知识管理系统
log('→ 运行知识系统初始化脚本...')
const initResult = await agent(
  `运行知识管理系统初始化:

   执行: bash scripts/init-knowledge-system.sh

   任务：
   1. 检查 Git Hook 状态
   2. 验证文档索引
   3. 检查 GitHub Actions 配置
   4. 设置向量数据库配置
   5. 检测依赖状态

   输出系统状态报告`,
  {
    label: '初始化知识系统',
    phase: '知识系统初始化'
  }
)

log(`✓ 知识管理系统初始化完成`)

// 6.3 验证所有组件
log('→ 验证知识管理系统组件...')
const verifyResult = await agent(
  `验证知识管理系统的所有组件:

   检查项：
   1. Git Hook (.git/hooks/post-commit) - 自动更新
   2. 文档索引 (docs/exploration/INDEX.md) - 已生成
   3. GitHub Actions workflows - 已配置
   4. 知识状态文件 (.knowledge-system.json) - 已创建
   5. 脚本文件完整性 (scripts/*.sh, scripts/*.py)

   输出验证报告`,
  {
    label: '验证系统组件',
    phase: '知识系统初始化'
  }
)

log(`✓ 系统验证完成`)

// ============================================================
// 返回完整的探索结果
// ============================================================
return {
  projectScan: scanResult,
  architecture: archResult,
  domain: domainResult,
  fileAnalyses: validAnalyses,
  knowledgeReport: knowledgeReport,

  // 新增：知识管理系统状态
  knowledgeSystem: {
    indexGenerated: true,
    systemInitialized: true,
    componentsVerified: true,
    features: {
      gitHook: '✅ 自动更新（已激活）',
      docIndex: '✅ 文档索引（已生成）',
      scheduledTasks: '✅ 定时任务（GitHub Actions）',
      vectorDB: '⚠️ 向量数据库（需安装依赖）'
    }
  },

  // 生成摘要
  summary: {
    totalFiles: scanResult.fileCount,
    layersIdentified: archResult.layers.length,
    domainsAnalyzed: domainResult.domains.length,
    filesDeepDived: validAnalyses.length,
    keyInsights: knowledgeReport.architectureHighlights.slice(0, 5),
    nextSteps: [
      '✅ 知识管理系统已初始化（A、B、C、D 标配）',
      '✅ 查看文档索引: docs/exploration/INDEX.md',
      '✅ 查看系统指南: docs/KNOWLEDGE_MANAGEMENT_SYSTEM.md',
      '⚙️ 可选：安装向量数据库依赖进行语义搜索',
      '📖 根据学习路径深入学习项目'
    ]
  },

  metadata: {
    totalAgentsUsed: 1 + 1 + 1 + validAnalyses.length + 1 + 3,
    estimatedDuration: '5-10 分钟',
    knowledgeSystemVersion: '1.0 (标配版)',
    features: 'Git Hook + 文档索引 + 定时任务 + 向量数据库'
  }
}

