function detectKnowledgeToPreserve(fileAnalyses, archResult, domainResult) {
  const knowledgeTopics = []

  // 从架构分析中提取需要沉淀的主题
  if (archResult?.layers) {
    archResult.layers.forEach(layer => {
      if (layer.keyComponents?.length > 0) {
